import {
  MapContainer,
  TileLayer,
  Polyline,
  useMap,
} from "react-leaflet";
import { useState, useEffect } from "react";
import PlaneMarker from "../components/PlaneMarker";
import "leaflet/dist/leaflet.css";
import "./Dashboard.css";

// 🔧 Fix map rendering issue
function FixMap() {
  const map = useMap();
  setTimeout(() => {
    map.invalidateSize();
  }, 100);
  return null;
}

export default function Dashboard() {
  const [flightNo, setFlightNo] = useState("");
  const [position, setPosition] = useState([20, 77]);
  const [flightData, setFlightData] = useState(null);
  const [trail, setTrail] = useState([]);

  const fetchFlight = async () => {
    try {
      const res = await fetch(
        `http://localhost:5000/api/flights/${flightNo}`
      );
      const data = await res.json();

      if (data.error) {
        alert(data.error);
        return;
      }

      const { latitude, longitude } = data;

      // ✨ Smooth movement
      setPosition((prev) => [
        prev[0] + (latitude - prev[0]) * 0.2,
        prev[1] + (longitude - prev[1]) * 0.2,
      ]);

      setFlightData(data);

      // ✈️ Trail
      setTrail((prev) => [...prev, [latitude, longitude]]);
    } catch (err) {
      console.error(err);
    }
  };

  // 🔄 Live refresh
  useEffect(() => {
    if (!flightData) return;
    const interval = setInterval(fetchFlight, 4000);
    return () => clearInterval(interval);
  }, [flightData]);

  return (
    <div className="dashboard">
      {/* 🔴 SIDE PANEL */}
      <div className="panel">
        <h2>✈️ Flight Tracker Pro</h2>

        <input
          value={flightNo}
          onChange={(e) => setFlightNo(e.target.value)}
          placeholder="Enter Flight (AI202)"
        />

        <button onClick={fetchFlight}>Track</button>

        {flightData && (
          <div className="details">
            <h3>{flightData.callsign}</h3>
            <p>🌍 {flightData.country}</p>
            <p>🛫 Alt: {Math.round(flightData.altitude)}</p>
            <p>⚡ Speed: {Math.round(flightData.velocity)}</p>
            <p>🆔 ICAO: {flightData.icao24}</p>
          </div>
        )}
      </div>

      {/* 🌍 MAP */}
      <MapContainer
        center={position}
        zoom={5}
        className="map"
        key={position.toString()}
      >
        <FixMap />

        <TileLayer url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png" />

        <PlaneMarker position={position} flightData={flightData} />

        {trail.length > 1 && (
          <Polyline
            positions={trail}
            pathOptions={{
              color: "red",
              weight: 3,
              opacity: 0.8,
            }}
          />
        )}
      </MapContainer>
    </div>
  );
}
